fn fill(grid: &mut [u8; 81]) -> bool {
    for i in 0..81 {
        if grid[i] == 0 {
            let allowed: Vec<u8> = get_allowed(&grid, i / 9, i % 9);
            for digit in allowed {
                grid[i] = digit;
                fill(grid);
                if fill(grid) {
                    return true;
                }
                grid[i] = 0;
            }
            return false;
        }
